    public ImmutableArray<AudioSegment> With(AudioSegment other)
    {
        var result = new AudioSegment[Length];
        result[0] = this;

        for (var i = 1; i < Length; i++)
        {
            AudioSegment slice = new() { Label = Label };
            ((ReadOnlySpan<float>)_array)[..^i].CopyTo(slice._array[..^i]);
            ((ReadOnlySpan<float>)other._array)[^i..].CopyTo(slice._array[^i..]);
            result[i] = slice;
        }

        return ImmutableCollectionsMarshal.AsImmutableArray(result);
    }
}
